import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  convertBase64ToUint8Array,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelartFailedResponseHandler } from './pixelart-error';
import type { PixelArtImageModelId } from './pixelart-image-settings';

const pixelartImageProviderOptionsSchema = z.object({
  size: z.string().optional(),
  style: z.enum(['pixel', 'retro', '8bit']).optional(),
  pixelDensity: z.number().optional(),
});

type PixelArtImageProviderOptions = z.infer<
  typeof pixelartImageProviderOptionsSchema
>;

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

const pixelartImageResponseSchema = z.object({
  data: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
  created: z.number().nullish(),
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use `size` in providerOptions.pixelart instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageProviderOptionsSchema,
    });

    const resolvedSize = pixelartOptions?.size ?? size;
    const resolvedStyle = pixelartOptions?.style;
    const resolvedPixelDensity = pixelartOptions?.pixelDensity;

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      response_format: 'b64_json',
    };

    if (resolvedSize != null) {
      body.size = resolvedSize;
    }
    if (resolvedStyle != null) {
      body.style = resolvedStyle;
    }
    if (resolvedPixelDensity != null) {
      body.pixel_density = resolvedPixelDensity;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item =>
        convertBase64ToUint8Array(item.b64_json),
      ),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: response.created ?? undefined,
        },
      },
    };
  }
}

